final class IntegrityChecker {
    
    static let shared = IntegrityChecker()
    
    private init() {}
    
    struct IntegrityResult {
        let isJailbroken: Bool
        let isDebugged: Bool
        let isTampered: Bool
        let isRunningInEmulator: Bool
        let isProxyDetected: Bool
        
        var isCompromised: Bool {
            return isJailbroken || isDebugged || isTampered || isRunningInEmulator
        }
    }
    
    func performFullCheck() -> IntegrityResult {
        return IntegrityResult(
            isJailbroken: checkJailbreak(),
            isDebugged: checkDebugger(),
            isTampered: checkTampering(),
            isRunningInEmulator: checkEmulator(),
            isProxyDetected: checkProxy()
        )
    }
    
    // MARK: - Jailbreak Detection
    
    private func checkJailbreak() -> Bool {
        // Check 1: Known jailbreak file paths
        let jailbreakPaths = [
            "/Applications/Cydia.app",
            "/Applications/Sileo.app",
            "/Applications/Zebra.app",
            "/Library/MobileSubstrate/MobileSubstrate.dylib",
            "/bin/bash",
            "/usr/sbin/sshd",
            "/etc/apt",
            "/private/var/lib/apt/",
            "/usr/lib/TweakInject",
            "/var/lib/dpkg/info",
            "/Library/MobileSubstrate/DynamicLibraries",
            "/usr/bin/ssh",
            "/private/var/stash",
            "/private/var/tmp/cydia.log",
            "/var/mobile/Library/SBSettings/Themes",
            "/Library/PreferenceBundles/SubstituteSettings.bundle",
            "/private/var/lib/cydia",
            "/usr/libexec/cydia"
        ]
        
        for path in jailbreakPaths {
            if FileManager.default.fileExists(atPath: path) {
                return true
            }
        }
        
        // Check 2: Can write to restricted paths
        let testPath = "/private/jailbreak_test_\(UUID().uuidString)"
        do {
            try "test".write(toFile: testPath, atomically: true, encoding: .utf8)
            try FileManager.default.removeItem(atPath: testPath)
            return true
        } catch {
            // Expected behavior on non-jailbroken device
        }
        
        // Check 3: Check for Cydia URL scheme
        if let url = URL(string: "cydia://package/com.example.package") {
            if UIApplication.shared.canOpenURL(url) {
                return true
            }
        }
        
        if let url = URL(string: "sileo://package/com.example.package") {
            if UIApplication.shared.canOpenURL(url) {
                return true
            }
        }
        
        // Check 4: Check if sandbox is intact
        let pid = getpid()
        var info = kinfo_proc()
        var size = MemoryLayout<kinfo_proc>.stride
        var mib: [Int32] = [CTL_KERN, KERN_PROC, KERN_PROC_PID, pid]
        let result = sysctl(&mib, UInt32(mib.count), &info, &size, nil, 0)
        if result == 0 {
            // Check for suspicious flags
        }
        
        // Check 5: Check for suspicious dylibs
        let suspiciousDylibs = [
            "SubstrateLoader",
            "SSLKillSwitch",
            "MobileSubstrate",
            "TweakInject",
            "CydiaSubstrate",
            "cynject",
            "libcycript",
            "FridaGadget",
            "frida-agent",
            "libfrida"
        ]
        
        let imageCount = _dyld_image_count()
        for i in 0..<imageCount {
            if let imageName = _dyld_get_image_name(i) {
                let name = String(cString: imageName)
                for dylib in suspiciousDylibs {
                    if name.lowercased().contains(dylib.lowercased()) {
                        return true
                    }
                }
            }
        }
        
        // Check 6: Fork check (jailbroken devices can fork)
        let forkResult = fork()
        if forkResult >= 0 {
            if forkResult > 0 {
                kill(forkResult, SIGTERM)
            }
            return true
        }
        
        // Check 7: Symbolic link checks
        let symlinks = [
            "/Applications",
            "/var/stash/Library/Ringtones",
            "/var/stash/Library/Wallpaper",
            "/var/stash/usr/include",
            "/var/stash/usr/libexec",
            "/var/stash/usr/share"
        ]
        
        for link in symlinks {
            var s = stat()
            if lstat(link, &s) == 0 {
                if (s.st_mode & S_IFLNK) == S_IFLNK {
                    return true
                }
            }
        }
        
        return false
    }
    
    // MARK: - Debugger Detection
    
    private func checkDebugger() -> Bool {
        var info = kinfo_proc()
        var size = MemoryLayout<kinfo_proc>.stride
        var mib: [Int32] = [CTL_KERN, KERN_PROC, KERN_PROC_PID, getpid()]
        
        let result = sysctl(&mib, UInt32(mib.count), &info, &size, nil, 0)
        
        if result == 0 {
            return (info.kp_proc.p_flag & P_TRACED) != 0
        }
        
        return false
    }
    
    // MARK: - Tampering Detection
    
    private func checkTampering() -> Bool {
        // Check if the app binary has been modified
        guard let bundlePath = Bundle.main.bundlePath as NSString? else { return true }
        
        // Check embedded.mobileprovision
        let provisionPath = bundlePath.appendingPathComponent("embedded.mobileprovision")
        
        // Check Info.plist integrity
        guard let infoPlist = Bundle.main.infoDictionary else { return true }
        guard let bundleId = infoPlist["CFBundleIdentifier"] as? String else { return true }
        
        // Verify bundle identifier hasn't been changed
        let expectedBundleIds = ["com.cryptowallet.app"] // Add your bundle ID
        if !expectedBundleIds.contains(bundleId) {
