        let task = SecTaskCreateFromSelf(nil)
        if task == nil {
            return true
        }
        
        return false
    }
    
    // MARK: - Emulator Detection
    
    private func checkEmulator() -> Bool {
        #if targetEnvironment(simulator)
        return true
        #else
        // Check for simulator-specific environment variables
        if ProcessInfo.processInfo.environment["SIMULATOR_DEVICE_NAME"] != nil {
            return true
        }
        
        // Check hardware model
        var systemInfo = utsname()
        uname(&systemInfo)
        let machine = withUnsafePointer(to: &systemInfo.machine) {
            $0.withMemoryRebound(to: CChar.self, capacity: 1) {
                String(cString: $0)
            }
        }
        
        if machine.contains("x86") || machine.contains("i386") {
            return true
        }
        
        return false
        #endif
    }
    
    // MARK: - Proxy Detection
    
    private func checkProxy() -> Bool {
        guard let proxySettings = CFNetworkCopySystemProxySettings()?.takeRetainedValue() as? [String: Any] else {
            return false
        }
        
        if let httpProxy = proxySettings["HTTPProxy"] as? String, !httpProxy.isEmpty {
            return true
        }
        
        if let httpsProxy = proxySettings["HTTPSProxy"] as? String, !httpsProxy.isEmpty {
            return true
        }
        
        return false
    }
}

// MARK: - Secure Key Storage

final class SecureKeyStore {
    
    enum KeyStoreError: Error, LocalizedError {
        case keyGenerationFailed
        case keyStorageFailed(OSStatus)
        case keyRetrievalFailed(OSStatus)
        case keyDeletionFailed(OSStatus)
        case biometricAuthFailed
        case dataConversionFailed
        case encryptionFailed
        case decryptionFailed
        case integrityCheckFailed
        
        var errorDescription: String? {
            switch self {
            case .keyGenerationFailed: return "Failed to generate cryptographic key"
            case .keyStorageFailed(let status): return "Failed to store key: \(status)"
            case .keyRetrievalFailed(let status): return "Failed to retrieve key: \(status)"
            case .keyDeletionFailed(let status): return "Failed to delete key: \(status)"
            case .biometricAuthFailed: return "Biometric authentication failed"
            case .dataConversionFailed: return "Data conversion failed"
            case .encryptionFailed: return "Encryption failed"
            case .decryptionFailed: return "Decryption failed"
            case .integrityCheckFailed: return "Device integrity check failed"
            }
        }
    }
    
    private let serviceIdentifier = "com.cryptowallet.keystore"
    private let encryptionKeyTag = "com.cryptowallet.encryption.key"
    
    static let shared = SecureKeyStore()
    
    private init() {}
    
    // MARK: - Store Private Key in Keychain with Biometric Protection
    
    func storePrivateKey(_ privateKeyData: Data, forAddress address: String, requireBiometric: Bool = true) throws {
        // Integrity check before storing
        let integrity = IntegrityChecker.shared.performFullCheck()
        if integrity.isCompromised {
            throw KeyStoreError.integrityCheckFailed
        }
        
        // Encrypt the private key before storing
        let encryptedData = try encryptData(privateKeyData)
        
        // Create access control with biometric requirement
        var accessControlFlags: SecAccessControlCreateFlags = [.privateKeyUsage]
        if requireBiometric {
            accessControlFlags.insert(.biometryCurrentSet)
        }
        
        guard let accessControl = SecAccessControlCreateWithFlags(
            kCFAllocatorDefault,
            kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            accessControlFlags,
            nil
        ) else {
            throw KeyStoreError.keyStorageFailed(-1)
        }
        
        // Delete existing key if present
        let deleteQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: address
        ]
        SecItemDelete(deleteQuery as CFDictionary)
        
        // Store encrypted key
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: address,
            kSecValueData as String: encryptedData,
            kSecAttrAccessControl as String: accessControl,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw KeyStoreError.keyStorageFailed(status)
        }
    }
    
    // MARK: - Retrieve Private Key with Biometric Auth
    
    func retrievePrivateKey(forAddress address: String) throws -> Data {
        // Integrity check before retrieval
        let integrity = IntegrityChecker.shared.performFullCheck()
        if integrity.isCompromised {
            throw KeyStoreError.integrityCheckFailed
        }
        
        let context = LAContext()
        context.localizedReason = "Authenticate to access your wallet"
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: address,
            kSecReturnData as String: true,
            kSecUseAuthenticationContext as String: context,
            kSecUseOperationPrompt as String: "Authenticate to sign transaction"
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let encryptedData = result as? Data else {
            throw KeyStoreError.keyRetrievalFailed(status)
        }
        
        // Decrypt the private key
        let decryptedData = try decryptData(encryptedData)
        return decryptedData
    }
    
    // MARK: - Delete Private Key
    
    func deletePrivateKey(forAddress address: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: address
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw KeyStoreError.keyDeletionFailed(status)
        }
    }
    
    // MARK: - List All Stored Addresses
    
    func listStoredAddresses() -> [String] {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecReturnAttributes as String: true,
            kSecMatchLimit as String: kSecMatchLimitAll
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let items = result as? [[String: Any]] else {
            return []
        }
        
        return items.compactMap { $0[kSecAttrAccount as String] as? String }
    }
    
    // MARK: - Encryption Layer (Defense in Depth)
    
    private func getOrCreateEncryptionKey() throws -> SymmetricKey {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: encryptionKeyTag.data(using: .utf8)!,
            kSecReturnData as String: true,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        if status == errSecSuccess, let keyData = result as? Data {
            return SymmetricKey(data: keyData)
        }
        
        // Generate new encryption key
        let key = SymmetricKey(size: .bits256)
        let keyData = key.withUnsafeBytes { Data($0) }
        
        let addQuery: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: encryptionKeyTag.data(using: .utf8)!,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let addStatus = SecItemAdd(addQuery as CFDictionary, nil)
        guard addStatus == errSecSuccess else {
            throw KeyStoreError.keyStorageFailed(addStatus)
        }
        
        return key
    }
    
    private func encryptData(_ data: Data) throws -> Data {
        let key = try getOrCreateEncryptionKey()
        
        guard let sealedBox = try? AES.GCM.seal(data, using: key) else {
            throw KeyStoreError.encryptionFailed
        }
        
        guard let combined = sealedBox.combined else {
            throw KeyStoreError.encryptionFailed
        }
        
        return combined
    }
    
    private func decryptData(_ data: Data) throws -> Data {
        let key = try getOrCreateEncryptionKey()
        
        guard let sealedBox = try? AES.GCM.SealedBox(combined: data) else {
            throw KeyStoreError.decryptionFailed
        }
        
        guard let decryptedData = try? AES.GCM.open(sealedBox, using: key) else {
            throw KeyStoreError.decryptionFailed
        }
        
        return decryptedData
    }
}

