final class CryptoEngine {
    
    enum CryptoError: Error, LocalizedError {
        case invalidPrivateKey
        case invalidPublicKey
        case signingFailed
        case hashingFailed
        case invalidMnemonic
        case keyDerivationFailed
        case integrityCheckFailed
        
        var errorDescription: String? {
            switch self {
            case .invalidPrivateKey: return "Invalid private key"
            case .invalidPublicKey: return "Invalid public key"
            case .signingFailed: return "Transaction signing failed"
            case .hashingFailed: return "Hashing failed"
            case .invalidMnemonic: return "Invalid mnemonic phrase"
            case .keyDerivationFailed: return "Key derivation failed"
            case .integrityCheckFailed: return "Device integrity check failed"
