        let publicKey: Data
        let address: String
    }
    
    func generateKeyPair() throws -> WalletKeyPair {
        // Integrity check
        let integrity = IntegrityChecker.shared.performFullCheck()
        if integrity.isCompromised {
            throw CryptoError.integrityCheckFailed
        }
        
        // Generate a new private key using secure random bytes
        let privateKey = P256.Signing.PrivateKey()
        let privateKeyData = privateKey.rawRepresentation
        let publicKeyData = privateKey.publicKey.rawRepresentation
        
        // Derive address from public key (Ethereum-style for MVP)
        let address = try deriveAddress(from: publicKeyData)
        
        return WalletKeyPair(
            privateKey: privateKeyData,
            publicKey: publicKeyData,
            address: address
        )
