    func generateMnemonic(wordCount: Int = 12) throws -> String {
        guard wordCount == 12 || wordCount == 24 else {
            throw CryptoError.invalidMnemonic
        }
        
        let entropyBytes = wordCount == 12 ? 16 : 32
        var entropy = Data(count: entropyBytes)
        let result = entropy.withUnsafeMutableBytes {
            SecRandomCopyBytes(kSecRandomDefault, entropyBytes, $0.baseAddress!)
        }
        
        guard result == errSecSuccess else {
            throw CryptoError.keyDerivationFailed
        }
        
        // Convert entropy to mnemonic words
        var words: [String] = []
        let hash = SHA256.hash(data: entropy)
        let hashByte = Array(hash)[0]
        
        var bits = ""
        for byte in entropy {
            bits += String(byte, radix: 2).leftPadded(toLength: 8, withPad: "0")
        }
        
        // Add checksum bits
        let checksumBits = wordCount == 12 ? 4 : 8
        let checksumString = String(hashByte, radix: 2).leftPadded(toLength: 8, withPad: "0")
        bits += String(checksumString.prefix(checksumBits))
        
        // Split into 11-bit groups
        let totalBits = (entropyBytes * 8) + checksumBits
        for i in stride(from: 0, to: totalBits, by: 11) {
            let start = bits.index(bits.startIndex, offsetBy: i)
            let end = bits.index(start, offsetBy: min(11, bits.distance(from: start, to: bits.endIndex)))
            let indexStr = String(bits[start..<end])
            if let index = Int(indexStr, radix: 2), index < wordList.count {
                words.append(wordList[index])
            } else {
                // Wrap around for MVP
                let wrappedIndex = (Int(indexStr, radix: 2) ?? 0) % wordList.count
                words.append(wordList[wrappedIndex])
            }
        }
        
        return words.joined(separator: " ")
    }
    
    func deriveKeyFromMnemonic(_ mnemonic: String, passphrase: String = "") throws -> WalletKeyPair {
        let mnemonicData = mnemonic.decomposedStringWithCompatibilityMapping.data(using: .utf8)!
        let salt = ("mnemonic" + passphrase).decomposedStringWithCompatibilityMapping.data(using: .utf8)!
        
        // PBKDF2 key derivation
        let seed = try pbkdf2(password: mnemonicData, salt: salt, iterations: 2048, keyLength: 64)
        
        // Use first 32 bytes as private key
        let privateKeyData = seed.prefix(32)
        
        // Create P256 key from derived data (for MVP)
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let publicKeyData = privateKey.publicKey.rawRepresentation
        let address = try deriveAddress(from: publicKeyData)
        
        return WalletKeyPair(
            privateKey: Data(privateKeyData),
            publicKey: publicKeyData,
            address: address
        )
    }
    
    private func pbkdf2(password: Data, salt: Data, iterations: Int, keyLength: Int) throws -> Data {
        var derivedKey = Data(count: keyLength)
        
        let result = derivedKey.withUnsafeMutableBytes { derivedKeyBytes in
            password.withUnsafeBytes { passwordBytes in
                salt.withUnsafeBytes { saltBytes in
                    CCKeyDerivationPBKDF(
                        CCPBKDFAlgorithm(kCCPBKDF2),
                        passwordBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                        password.count,
                        saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        salt.count,
                        CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA512),
                        UInt32(iterations),
                        derivedKeyBytes.baseAddress?.assumingMemoryBound(to: UInt8.self),
                        keyLength
                    )
                }
            }
        }
        
        guard result == kCCSuccess else {
            throw CryptoError.keyDerivationFailed
        }
        
        return derivedKey
    }
    
    // MARK: - Address Derivation
    
    func deriveAddress(from publicKey: Data) throws -> String {
        // Keccak-256 hash of public key, take last 20 bytes (Ethereum-style)
        let hash = SHA256.hash(data: publicKey)
        let hashData = Data(hash)
        let addressBytes = hashData.suffix(20)
        return "0x" + addressBytes.map { String(format: "%02x", $0) }.joined()
    }
    
    // MARK: - Transaction Signing
    
    func signTransaction(_ transaction: Transaction, withPrivateKey privateKeyData: Data) throws -> SignedTransaction {
        // Integrity check
        let integrity = IntegrityChecker.shared.performFullCheck()
        if integrity.isCompromised {
            throw CryptoError.integrityCheckFailed
        }
        
        // Serialize transaction for signing
        let transactionData = try transaction.serialize()
        
        // Hash the transaction
        let hash = SHA256.hash(data: transactionData)
        let hashData = Data(hash)
        
        // Sign with private key
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let signature = try privateKey.signature(for: hashData)
        
        return SignedTransaction(
            transaction: transaction,
            signature: signature.rawRepresentation,
            transactionHash: hashData.hexString
        )
    }
    
    // MARK: - Signature Verification
    
    func verifySignature(_ signedTransaction: SignedTransaction, publicKeyData: Data) throws -> Bool {
        let transactionData = try signedTransaction.transaction.serialize()
        let hash = SHA256.hash(data: transactionData)
        let hashData = Data(hash)
        
        let publicKey = try P256.Signing.PublicKey(rawRepresentation: publicKeyData)
        let signature = try P256.Signing.ECDSASignature(rawRepresentation: signedTransaction.signature)
        
        return publicKey.isValidSignature(signature, for: hashData)
    }
    
    // MARK: - Secure Memory Wipe
    
    func secureWipe(_ data: inout Data) {
        data.withUnsafeMutableBytes { buffer in
            if let baseAddress = buffer.baseAddress {
                memset_s(baseAddress, buffer.count, 0, buffer.count)
            }
        }
    }
}

// MARK: - Transaction Models

struct Transaction: Codable {
    let from: String
    let to: String
    let value: String // Wei value as string
    let nonce: UInt64
    let gasPrice: String
    let gasLimit: UInt64
    let data: String? // Contract data
    let chainId: Int
    let timestamp: Date
    
    func serialize() throws -> Data {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        encoder.outputFormatting = .sortedKeys // Deterministic serialization
        return try encoder.encode(self)
    }
}

struct SignedTransaction {
    let transaction: Transaction
    let signature: Data
    let transactionHash: String
    
    var rawTransaction: String {
        return signature.hexString
    }
}

// MARK: - Blockchain Communication

final class BlockchainClient {
    
    enum BlockchainError: Error, LocalizedError {
        case invalidURL
        case networkError(Error)
        case invalidResponse
        case rpcError(String)
        case rateLimited
        case sslPinningFailed
        
        var errorDescription: String? {
            switch self {
            case .invalidURL: return "Invalid blockchain node URL"
            case .networkError(let error): return "Network error: \(error.localizedDescription)"
            case .invalidResponse: return "Invalid response from blockchain"
            case .rpcError(let message): return "RPC error: \(message)"
            case .rateLimited: return "Rate limited, please try again later"
            case .sslPinningFailed: return "SSL certificate validation failed"
            }
        }
    }
    
    struct RPCRequest: Codable {
        let jsonrpc: String
        let method: String
        let params: [RPCParam]
        let id: Int
    }
    
    enum RPCParam: Codable {
        case string(String)
        case int(Int)
        case dict([String: String])
        case array([String])
        
        func encode(to encoder: Encoder) throws {
            var container = encoder.singleValueContainer()
            switch self {
            case .string(let value): try container.encode(value)
            case .int(let value): try container.encode(value)
            case .dict(let value): try container.encode(value)
            case .array(let value): try container.encode(value)
            }
        }
        
        init(from decoder: Decoder) throws {
            let container = try decoder.singleValueContainer()
            if let value = try? container.decode(String.self) {
                self = .string(value)
            } else if let value = try? container.decode(Int.self) {
                self = .int(value)
            } else if let value = try? container.decode([String: String].self) {
                self = .dict(value)
            } else if let value = try? container.decode([String].self) {
                self = .array(value)
            } else {
                throw DecodingError.typeMismatch(RPCParam.self, DecodingError.Context(codingPath: decoder.codingPath, debugDescription: "Unknown type"))
            }
        }
    }
    
    struct RPCResponse: Codable {
        let jsonrpc: String
        let id: Int
        let result: String?
        let error: RPCErrorResponse?
    }
    
    struct RPCErrorResponse: Codable {
        let code: Int
        let message: String
    }
    
    private let nodeURL: URL
    private let session: URLSession
    private var requestId: Int = 0
    
    // SSL Pinning delegate
    private let pinningDelegate: SSLPinningDelegate
    
    init(nodeURLString: String, pinnedCertificates: [Data] = []) throws {
        guard let url = URL(string: nodeURLString) else {
            throw BlockchainError.invalidURL
        }
        self.nodeURL = url
        self.pinningDelegate = SSLPinningDelegate(pinnedCertificates: pinnedCertificates)
        
        let config = URLSessionConfiguration.ephemeral
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        // Disable caching for sensitive data
        config.urlCache = nil
        config.requestCachePolicy = .reloadIgnoringLocalAndRemoteCacheData
        
        self.session = URLSession(configuration: config, delegate: pinningDelegate, delegateQueue: nil)
    }
    
    private func nextRequestId() -> Int {
        requestId += 1
        return requestId
    }
    
    // MARK: - Get Balance
    
    func getBalance(address: String) async throws -> String {
        let request = RPCRequest(
            jsonrpc: "2.0",
            method: "eth_getBalance",
            params: [.string(address), .string("latest")],
            id: nextRequestId()
        )
        
        let response = try await sendRPCRequest(request)
        
        guard let result = response.result else {
            throw BlockchainError.invalidResponse
        }
        
        return result
    }
    
    // MARK: - Get Transaction Count (Nonce)
    
    func getTransactionCount(address: String) async throws -> UInt64 {
        let request = RPCRequest(
            jsonrpc: "2.0",
            method: "eth_getTransactionCount",
            params: [.string(address), .string("latest")],
            id: nextRequestId()
        )
        
        let response = try await sendRPCRequest(request)
        
        guard let result = response.result else {
            throw BlockchainError.invalidResponse
        }
        
        // Parse hex string to UInt64
        let hexString = result.hasPrefix("0x") ? String(result.dropFirst(2)) : result
        guard let nonce = UInt64(hexString, radix: 16) else {
            throw BlockchainError.invalidResponse
        }
        
        return nonce
    }
    
    // MARK: - Get Gas Price
    
    func getGasPrice() async throws -> String {
        let request = RPCRequest(
            jsonrpc: "2.0",
            method: "eth_gasPrice",
            params: [],
            id: nextRequestId()
        )
        
        let response = try await sendRPCRequest(request)
        
        guard let result = response.result else {
            throw BlockchainError.invalidResponse
        }
        
        return result
    }
    
    // MARK: - Send Raw Transaction
    
    func sendRawTransaction(_ signedTx: String) async throws -> String {
        let request = RPCRequest(
            jsonrpc: "2.0",
            method: "eth_sendRawTransaction",
            params: [.string(signedTx)],
            id: nextRequestId()
        )
        
        let response = try await sendRPCRequest(request)
        
        if let error = response.error {
            throw BlockchainError.rpcError(error.message)
        }
        
        guard let txHash = response.result else {
            throw BlockchainError.invalidResponse
        }
        
        return txHash
    }
    
    // MARK: - Get Transaction Receipt
    
    func getTransactionReceipt(txHash: String) async throws -> RPCResponse {
        let request = RPCRequest(
            jsonrpc: "2.0",
            method: "eth_getTransactionReceipt",
            params: [.string(txHash)],
            id: nextRequestId()
        )
        
        return try await sendRPCRequest(request)
    }
    
    // MARK: - Estimate Gas
    
    func estimateGas(from: String, to: String, value: String, data: String?) async throws -> String {
        var params: [String: String] = [
            "from": from,
            "to": to,
            "value": value
        ]
        if let data = data {
            params["data"] = data
        }
        
        let request = RPCRequest(
            jsonrpc: "2.0",
            method: "eth_estimateGas",
            params: [.dict(params)],
            id: nextRequestId()
        )
        
        let response = try await sendRPCRequest(request)
        
        guard let result = response.result else {
            throw BlockchainError.invalidResponse
        }
        
        return result
    }
    
    // MARK: - RPC Request Handler
    
    private func sendRPCRequest(_ rpcRequest: RPCRequest) async throws -> RPCResponse {
        var urlRequest = URLRequest(url: nodeURL)
        urlRequest.httpMethod = "POST"
        urlRequest.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let encoder = JSONEncoder()
        urlRequest.httpBody = try encoder.encode(rpcRequest)
        
        do {
            let (data, response) = try await session.data(for: urlRequest)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                throw BlockchainError.invalidResponse
            }
            
            if httpResponse.statusCode == 429 {
                throw BlockchainError.rateLimited
            }
            
            guard (200...299).contains(httpResponse.statusCode) else {
                throw BlockchainError.invalidResponse
            }
            
            let decoder = JSONDecoder()
            let rpcResponse = try decoder.decode(RPCResponse.self, from: data)
            
            if let error = rpcResponse.error {
                throw BlockchainError.rpcError(error.message)
            }
            
            return rpcResponse
        } catch let error as BlockchainError {
            throw error
        } catch {
            throw BlockchainError.networkError(error)
        }
    }
}

// MARK: - SSL Pinning Delegate

final class SSLPinningDelegate: NSObject, URLSessionDelegate {
    
    private let pinnedCertificates: [Data]
    
    init(pinnedCertificates: [Data]) {
        self.pinnedCertificates = pinnedCertificates
        super.init()
    }
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // If no pinned certificates, just validate the trust chain
        if pinnedCertificates.isEmpty {
            let policy = SecPolicyCreateSSL(true, challenge.protectionSpace.host as CFString)
            SecTrustSetPolicies(serverTrust, policy)
            
            var error: CFError?
            let isValid = SecTrustEvaluateWithError(serverTrust, &error)
            
            if isValid {
                completionHandler(.useCredential, URLCredential(trust: serverTrust))
            } else {
                completionHandler(.cancelAuthenticationChallenge, nil)
            }
            return
        }
        
        // Certificate pinning
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        var serverCertificates: [Data] = []
        
        for i in 0..<certificateCount {
            if let certificate = SecTrustGetCertificateAtIndex(serverTrust, i) {
                let certData = SecCertificateCopyData(certificate) as Data
                serverCertificates.append(certData)
            }
        }
        
        // Check if any server certificate matches our pinned certificates
        let isPinned = serverCertificates.contains { serverCert in
            pinnedCertificates.contains { pinnedCert in
                serverCert == pinnedCert
            }
        }
        
        if isPinned {
            completionHandler(.useCredential, URLCredential(trust: serverTrust))
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
}

// MARK: - Wallet Manager (Main Interface)

final class WalletManager: ObservableObject {
    
    enum WalletError: Error, LocalizedError {
        case walletNotFound
        case insufficientFunds
        case transactionFailed(String)
        case integrityCheckFailed
        case biometricNotAvailable
        case walletAlreadyExists
        
        var errorDescription: String? {
            switch self {
            case .walletNotFound: return "Wallet not found"
            case .insufficientFunds: return "Insufficient funds"
            case .transactionFailed(let msg): return "Transaction failed: \(msg)"
            case .integrityCheckFailed: return "Device integrity compromised"
            case .biometricNotAvailable: return "Biometric authentication not available"
            case .walletAlreadyExists: return "Wallet already exists"
            }
        }
    }
    
    struct WalletInfo {
        let address: String
        let publicKey: Data
        var balance: String?
        let createdAt: Date
    }
    
    @Published var currentWallet: WalletInfo?
    @Published var balance: String = "0"
    @Published var isLoading: Bool = false
    @Published var transactionHistory: [TransactionRecord] = []
    
    private let keyStore = SecureKeyStore.shared
    private let cryptoEngine = CryptoEngine.shared
    private var blockchainClient: BlockchainClient?
    
    static let shared = WalletManager()
    
    private init() {}
    
    // MARK: - Setup
    
    func configure(nodeURL: String, pinnedCertificates: [Data] = []) throws {
        self.blockchainClient = try BlockchainClient(nodeURLString: nodeURL, pinnedCertificates: pinnedCertificates)
    }
    
    // MARK: - Create New Wallet
    
    func createNewWallet() async throws -> (walletInfo: WalletInfo, mnemonic: String) {
        // Integrity check
        let integrity = IntegrityChecker.shared.performFullCheck()
        if integrity.isCompromised {
            throw WalletError.integrityCheckFailed
        }
        
        // Check biometric availability
        try checkBiometricAvailability()
        
        // Generate mnemonic
        let mnemonic = try cryptoEngine.generateMnemonic()
        
        // Derive key pair from mnemonic
        let keyPair = try cryptoEngine.deriveKeyFromMnemonic(mnemonic)
        
        // Store private key securely
        try keyStore.storePrivateKey(keyPair.privateKey, forAddress: keyPair.address)
        
        // Store public key (non-sensitive, but still in keychain)
        let publicKeyAddress = keyPair.address + "_pub"
        try keyStore.storePrivateKey(keyPair.publicKey, forAddress: publicKeyAddress, requireBiometric: false)
        
        let walletInfo = WalletInfo(
            address: keyPair.address,
            publicKey: keyPair.publicKey,
            balance: nil,
            createdAt: Date()
        )
        
        await MainActor.run {
            self.currentWallet = walletInfo
        }
        
        // Securely wipe sensitive data from memory
        var mutablePrivateKey = keyPair.privateKey
        cryptoEngine.secureWipe(&mutablePrivateKey)
        
        return (walletInfo, mnemonic)
    }
    
    // MARK: - Import Wallet from Mnemonic
    
    func importWallet(mnemonic: String, passphrase: String = "") async throws -> WalletInfo {
        // Integrity check
        let integrity = IntegrityChecker.shared.performFullCheck()
        if integrity.isCompromised {
            throw WalletError.integrityCheckFailed
        }
        
        try checkBiometricAvailability()
        
        let keyPair = try cryptoEngine.deriveKeyFromMnemonic(mnemonic, passphrase: passphrase)
        
        // Store private key securely
        try keyStore.storePrivateKey(keyPair.privateKey, forAddress: keyPair.address)
        
        // Store public key
        let publicKeyAddress = keyPair.address + "_pub"
        try keyStore.storePrivateKey(keyPair.publicKey, forAddress: publicKeyAddress, requireBiometric: false)
        
        let walletInfo = WalletInfo(
            address: keyPair.address,
            publicKey: keyPair.publicKey,
            balance: nil,
            createdAt: Date()
        )
        
        await MainActor.run {
            self.currentWallet = walletInfo
        }
        
        var mutablePrivateKey = keyPair.privateKey
        cryptoEngine.secureWipe(&mutablePrivateKey)
        
        return walletInfo
    }
    
    // MARK: - Send Transaction
    
    func sendTransaction(to recipient: String, amount: String, data: String? = nil) async throws -> String {
        guard let wallet = currentWallet else {
            throw WalletError.walletNotFound
        }
        
        guard let client = blockchainClient else {
            throw WalletError.transactionFailed("Blockchain client not configured")
        }
        
        // Integrity check
        let integrity = IntegrityChecker.shared.performFullCheck()
        if integrity.isCompromised {
            throw WalletError.integrityCheckFailed
        }
        
        await MainActor.run { self.isLoading = true }
        defer { Task { @MainActor in self.isLoading = false } }
        
        // Get nonce
        let nonce = try await client.getTransactionCount(address: wallet.address)
        
        // Get gas price
        let gasPrice = try await client.getGasPrice()
        
        // Estimate gas
        let gasEstimate = try await client.estimateGas(
            from: wallet.address,
            to: recipient,
            value: amount,
            data: data
        )
        
        let gasLimit = UInt64(gasEstimate.dropFirst(2), radix: 16) ?? 21000
        
        // Create transaction
        let transaction = Transaction(
            from: wallet.address,
            to: recipient,
            value: amount,
            nonce: nonce,
            gasPrice: gasPrice,
            gasLimit: gasLimit,
            data: data,
            chainId: 1, // Mainnet
            timestamp: Date()
        )
        
        // Retrieve private key (triggers biometric auth)
        var privateKey = try keyStore.retrievePrivateKey(forAddress: wallet.address)
        
        defer {
            // Securely wipe private key from memory
            cryptoEngine.secureWipe(&privateKey)
        }
        
        // Sign transaction
        let signedTx = try cryptoEngine.signTransaction(transaction, withPrivateKey: privateKey)
        
        // Broadcast transaction
        let txHash = try await client.sendRawTransaction(signedTx.rawTransaction)
        
        // Record transaction
        let record = TransactionRecord(
            hash: txHash,
            from: wallet.address,
            to: recipient,
            value: amount,
            timestamp: Date(),
            status: .pending
        )
        
        await MainActor.run {
            self.transactionHistory.insert(record, at: 0)
        }
        
        return txHash
    }
    
    // MARK: - Refresh Balance
    
    func refreshBalance() async throws {
        guard let wallet = currentWallet else {
            throw WalletError.walletNotFound
        }
        
        guard let client = blockchainClient else {
            throw WalletError.transactionFailed("Blockchain client not configured")
        }
        
        let balanceHex = try await client.getBalance(address: wallet.address)
        
        // Convert hex to decimal string
        let hexString = balanceHex.hasPrefix("0x") ? String(balanceHex.dropFirst(2)) : balanceHex
        let balanceWei = UInt64(hexString, radix: 16) ?? 0
        let balanceEth = Double(balanceWei) / 1e18
        
        await MainActor.run {
            self.balance = String(format: "%.6f", balanceEth)
        }
    }
    
    // MARK: - Delete Wallet
    
    func deleteWallet() throws {
        guard let wallet = currentWallet else {
            throw WalletError.walletNotFound
        }
        
        try keyStore.deletePrivateKey(forAddress: wallet.address)
        try keyStore.deletePrivateKey(forAddress: wallet.address + "_pub")
        
        DispatchQueue.main.async {
            self.currentWallet = nil
            self.balance = "0"
            self.transactionHistory = []
        }
    }
    
    // MARK: - List Wallets
    
    func listWallets() -> [String] {
        return keyStore.listStoredAddresses().filter { !$0.hasSuffix("_pub") }
    }
    
    // MARK: - Biometric Check
    
    private func checkBiometricAvailability() throws {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            // Fall back to passcode
            guard context.canEvaluatePolicy(.deviceOwnerAuthentication, error: &error) else {
                throw WalletError.biometricNotAvailable
            }
            return
        }
    }
}

// MARK: - Transaction Record

struct TransactionRecord: Identifiable, Codable {
    let id: UUID
    let hash: String
    let from: String
    let to: String
    let value: String
    let timestamp: Date
    var status: TransactionStatus
    
    init(hash: String, from: String, to: String, value: String, timestamp: Date, status: TransactionStatus) {
        self.id = UUID()
        self.hash = hash
        self.from = from
        self.to = to
        self.value = value
        self.timestamp = timestamp
        self.status = status
    }
    
    enum TransactionStatus: String, Codable {
        case pending
        case confirmed
        case failed
    }
}

// MARK: - Rate Limiter

final class RateLimiter {
    private var requestTimestamps: [Date] = []
    private let maxRequests: Int
    private let timeWindow: TimeInterval
    private let queue = DispatchQueue(label: "com.cryptowallet.ratelimiter")
    
    init(maxRequests: Int = 10, timeWindow: TimeInterval = 60) {
        self.maxRequests = maxRequests
        self.timeWindow = timeWindow
    }
    
    func shouldAllowRequest() -> Bool {
        queue.sync {
            let now = Date()
            requestTimestamps = requestTimestamps.filter { now.timeIntervalSince($0) < timeWindow }
            
            if requestTimestamps.count < maxRequests {
                requestTimestamps.append(now)
                return true
            }
            
            return false
        }
    }
}

// MARK: - Anti-Tampering Monitor

final class SecurityMonitor {
    
    static let shared = SecurityMonitor()
    
    private var timer: Timer?
    private var onCompromiseDetected: (() -> Void)?
    
    private init() {}
    
    func startMonitoring(onCompromise: @escaping () -> Void) {
        self.onCompromiseDetected = onCompromise
        
        // Periodic integrity checks
        timer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { [weak self] _ in
            self?.performCheck()
        }
        
        // Initial check
        performCheck()
    }
    
    func stopMonitoring() {
        timer?.invalidate()
        timer = nil
    }
    
    private func performCheck() {
        DispatchQueue.global(qos: .utility).async { [weak self] in
            let result = IntegrityChecker.shared.performFullCheck()
            
            if result.isCompromised {
                DispatchQueue.main.async {
                    self?.onCompromiseDetected?()
                }
            }
        }
    }
}

// MARK: - Secure Data Wiper (Emergency)

final class EmergencyWiper {
    
    static func wipeAllWalletData() {
        // Delete all keychain items for our service
        let secClasses = [
            kSecClassGenericPassword,
            kSecClassKey,
            kSecClassCertificate,
            kSecClassIdentity
        ]
        
        for secClass in secClasses {
            let query: [String: Any] = [
                kSecClass as String: secClass
            ]
            SecItemDelete(query as CFDictionary)
        }
        
        // Clear UserDefaults
        if let bundleId = Bundle.main.bundleIdentifier {
            UserDefaults.standard.removePersistentDomain(forName: bundleId)
        }
        
        // Clear any cached files
        if let cacheDir = FileManager.default.urls(for: .cachesDirectory, in: .userDomainMask).first {
            try? FileManager.default.removeItem(at: cacheDir)
        }
        
        // Clear documents directory
        if let docsDir = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask).first {
            try? FileManager.default.removeItem(at: docsDir)
        }
    }
}

// MARK: - Extensions

extension Data {
    var hexString: String {
        return map { String(format: "%02x", $0) }.joined()
    }
    
    init?(hexString: String) {
        let hex = hexString.hasPrefix("0x") ? String(hexString.dropFirst(2)) : hexString
        let len = hex.count / 2
        var data = Data(capacity: len)
        var index = hex.startIndex
        
        for _ in 0..<len {
            let nextIndex = hex.index(index, offsetBy: 2)
            guard let byte = UInt8(hex[index..<nextIndex], radix: 16) else { return nil }
            data.append(byte)
            index = nextIndex
        }
        
        self = data
    }
}

extension String {
    func leftPadded(toLength length: Int, withPad pad: Character) -> String {
        let deficit = length - self.count
        if deficit <= 0 { return self }
        return String(repeating: pad, count: deficit) + self
    }
}

// MARK: - SwiftUI Views

import SwiftUI

struct WalletApp: App {
    @StateObject private var walletManager = WalletManager.shared
    
    init() {
        // Start security monitoring
        SecurityMonitor.shared.startMonitoring {
            // Handle compromise - show alert and optionally wipe
            NotificationCenter.default.post(name: .deviceCompromised, object: nil)
        }
    }
    
    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(walletManager)
        }
    }
}

extension Notification.Name {
    static let deviceCompromised = Notification.Name("deviceCompromised")
}

struct ContentView: View {
    @EnvironmentObject var walletManager: WalletManager
    @State private var showCreateWallet = false
    @State private var showImportWallet = false
    @State private var showSendTransaction = false
    @State private var showSecurityAlert = false
    @State private var mnemonicToShow: String?
    @State private var errorMessage: String?
    @State private var showError = false
    
    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
                if let wallet = walletManager.currentWallet {
                    // Wallet Dashboard
                    WalletDashboardView(wallet: wallet)
                } else {
                    // No Wallet - Setup
                    WalletSetupView(
                        showCreateWallet: $showCreateWallet,
                        showImportWallet: $showImportWallet
                    )
                }
            }
            .navigationTitle("Crypto Wallet")
            .toolbar {
                if walletManager.currentWallet != nil {
                    ToolbarItem(placement: .navigationBarTrailing) {
                        Button("Send") {
                            showSendTransaction = true
                        }
                    }
                }
            }
            .sheet(isPresented: $showCreateWallet) {
                CreateWalletView(mnemonicToShow: $mnemonicToShow)
            }
            .sheet(isPresented: $showImportWallet) {
                ImportWalletView()
            }
            .sheet(isPresented: $showSendTransaction) {
                SendTransactionView()
            }
            .sheet(item: Binding(
                get: { mnemonicToShow.map { MnemonicWrapper(mnemonic: $0) } },
                set: { mnemonicToShow = $0?.mnemonic }
            )) { wrapper in
                MnemonicDisplayView(mnemonic: wrapper.mnemonic)
            }
            .alert("Security Warning", isPresented: $showSecurityAlert) {
                Button("Wipe Data", role: .destructive) {
                    EmergencyWiper.wipeAllWalletData()
                }
                Button("Continue Anyway", role: .cancel) {}
            } message: {
                Text("This device may be compromised. Your wallet security cannot be guaranteed. It is recommended to transfer funds immediately.")
            }
            .alert("Error", isPresented: $showError) {
                Button("OK", role: .cancel) {}
            } message: {
                Text(errorMessage ?? "Unknown error")
            }
            .onReceive(NotificationCenter.default.publisher(for: .deviceCompromised)) { _ in
                showSecurityAlert = true
            }
        }
    }
}

